const response = $input.first().json;
const content = response.choices?.[0]?.message?.content || '{}';

let topicData;
try {
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  topicData = JSON.parse(jsonMatch ? jsonMatch[0] : content);
} catch(e) {
  topicData = {
    topic: 'AI Agent Orchestration Patterns',
    search_query: 'AI agent orchestration',
    why_surprising: 'Fallback topic due to parse error',
    initial_thesis: 'AI agent orchestration is becoming critical for multi-agent systems.'
  };
}

return [{ json: topicData }];

const topic = $('Parse Topic').first().json;
const hnResults = $('Search HN for Topic').first().json;
const redditResults = $('Search Reddit for Topic').first().json;

// Extract HN hits
const hnHits = (hnResults.hits || []).slice(0, 5).map(h => 
  `- [HN] ${h.title} (${h.points} pts) - https://news.ycombinator.com/item?id=${h.objectID}`
).join('\n');

// Extract Reddit posts
const redditPosts = (redditResults?.data?.children || []).slice(0, 5).map(p =>
  `- [Reddit] ${p.data.title} (${p.data.score} pts) - https://reddit.com${p.data.permalink}`
).join('\n');

const prompt = `You are writing a 2-page executive briefing for Nadav, owner of nVision Digital AI, an AI-focused digital agency in Israel.

TOPIC: ${topic.topic}
Why it's surprising: ${topic.why_surprising}
Initial thesis: ${topic.initial_thesis}

Related discussions found online:
${hnHits || 'No HN results found'}
${redditPosts || 'No Reddit results found'}

Write a comprehensive briefing in HTML format with:
1. **Executive Summary** (3-4 sentences)
2. **What's Happening** (detailed explanation with examples)
3. **Why It Matters for Digital Agencies** (specific implications)
4. **Opportunities & Action Items** (3-5 concrete steps Nadav could take)
5. **Timeline** (when this becomes mainstream)
6. **Sources & Further Reading** (include the links found above)

Use professional HTML formatting with inline styles. Make it visually clean and scannable. Use headers, bullet points, and subtle color accents (#2563eb for headers, #f8fafc background for callout boxes).`;

return [{ json: { prompt, topic: topic.topic, searchQuery: topic.search_query } }];

const response = $input.first().json;
const briefing = response.choices?.[0]?.message?.content || 'No briefing generated.';
const topic = $('Build Research Prompt').first().json.topic;

const jobPayload = {
  jobId: `surprise-research-${Date.now()}`,
  type: 'surprise-research',
  status: 'complete',
  timestamp: new Date().toISOString(),
  data: {
    topic,
    briefingHtml: briefing,
    searchQuery: $('Build Research Prompt').first().json.searchQuery
  }
};

const emailSubject = `Weekly Surprise Research: ${topic}`;

return [{ json: { ...jobPayload, emailSubject, emailBody: briefing } }];
